const https = require('https');
const http = require('http');
const { parse } = require('node-html-parser');

function fetchMetadata(url) {
    return new Promise((resolve, reject) => {
        const client = url.startsWith("https") ? https : http;

        client.get(url, (res) => {
            let data = '';

            res.on('data', chunk => {
                data += chunk;
            });

            res.on('end', () => {
                const root = parse(data);
                const metaTags = root.querySelectorAll('meta');
                const title = root.querySelector('title') ? root.querySelector('title').innerText : '';
                const metaDescription = metaTags.find(tag => tag.getAttribute('name') === 'description') || {};
                const metaOgTags = metaTags.filter(tag => tag.getAttribute('property') && tag.getAttribute('property').startsWith('og:'));

                const metadata = {
                    title: title,
                    description: metaDescription.getAttribute('content') || '',
                    ogTags: {}
                };

                metaOgTags.forEach(tag => {
                    metadata.ogTags[tag.getAttribute('property')] = tag.getAttribute('content');
                });

                resolve(metadata);
            });
        }).on('error', (e) => {
            reject(e);
        });
    });
}

exports.handler = async (req, res) => {
    const { url } = req.query;
    if (!url) {
        return res.status(400).send('URL is required');
    }

    try {
        const metadata = await fetchMetadata(url);
        res.status(200).json(metadata);
    } catch (error) {
        res.status(500).send('Error fetching metadata');
    }
};